new_law_data = """const List<LawArticle> law8103Data = [
  LawArticle(id: '1', title: 'تعريف المهنة', content: 'المفوض القضائي مساعد للقضاء، يمارس مهنة حرة وفقا لأحكام هذا القانون والنصوص التنظيمية المتعلقة بتطبيقه.'),
  LawArticle(id: '2', title: 'إحداث المكاتب', content: 'تحدث بدوائر المحاكم الابتدائية مكاتب للمفوضين القضائيين للقيام بالمهام المنوطة بهم طبقا لهذا القانون أمام مختلف محاكم المملكة.'),
  LawArticle(id: '3', title: 'حالات التنافي', content: 'تتنافى مهنة المفوض القضائي مع ممارسة أي وظيفة أو مهمة عمومية ومع كل نشاط تجاري أو صناعي أو معتبر كذلك بمقتضى القانون، كما تتنافى مع مهنة محام أو موثق أو عدل أو خبير أو ترجمان أو وكيل أعمال أو مهنة سمسار أو مستشار قانوني أو جبائي، ومع كل عمل خارج مهامه يؤدى عنه أجر باستثناء النشاطات العلمية.'),
  LawArticle(id: '4', title: 'شروط مزاولة المهنة', content: 'يشترط في المرشح لمزاولة مهنة مفوض قضائي :\\n1 - أن يكون من جنسية مغربية ؛\\n2 - أن يبلغ من العمر 25 سنة كاملة وأن لا يتجاوز 45 سنة، ما لم يكن معفى طبقا للمادة الخامسة بعده ؛\\n3 - أن يكون حاصلا على شهادة الإجازة في الحقوق أو ما يعادلها أو على شهادة الإجازة في الشريعة الإسلامية ؛\\n4 - أن يكون في وضعية سليمة بالنسبة إلى قانون الخدمة العسكرية ؛\\n5 - أن يكون متمتعا بحقوقه المدنية ؛\\n6 - أن يكون متمتعا بالقدرة الفعلية على ممارسة المهنة بكامل أعبائها ؛\\n7 - أن لا يكون محكوما عليه من أجل جناية، أو جنحة بعقوبة حبس نافذ أو موقوف التنفيذ باستثناء الجرائم غير العمدية، وأن لا يكون محكوما عليه بجريمة من جرائم الأموال ولو بمجرد غرامة ؛\\n8 - ألا يكون قد تعرض لأي عقوبة تأديبية، أو صدر في حقه حكم نهائي بعدم الأهلية لمزاولة مهنة بسبب اقترافه لفعل مخل بالشرف أو الأمانة ؛\\n9 - أن يكون قد نجح في المباراة لولوج مهنة المفوضين القضائيين، وأدى فترة التكوين ونجح في اختبار نهايته.'),
  LawArticle(id: '5', title: 'الإعفاء من المباراة', content: 'يعفى من المباراة فقط وفي حدود ثلث المكاتب الشاغرة :\\n- المنتدبون القضائيون الذين أثبتوا أنهم قضوا بهذه الصفة عشر سنوات على الأقل من العمل المتواصل بالمحاكم ؛\\n- المحررون القضائيون وكتاب الضبط الذين أثبتوا أنهم قضوا على الأقل خمسة عشرة سنة من العمل المتواصل بالمحاكم والحاصلون على الشهادة المشار إليها في الفقرة الثالثة من المادة الرابعة أعلاه.'),
  LawArticle(id: '6', title: 'كيفية إجراء المباراة', content: 'تحدد كيفية إجراء المباراة والتكوين واختبار نهايته بنص تنظيمي.'),
  LawArticle(id: '7', title: 'مشتملات التكوين', content: 'يشتمل التكوين على تأهيل نظري وتطبيقي وميداني.'),
  LawArticle(id: '8', title: 'التشطيب لعدم الالتزام', content: 'يمكن لوزير العدل وباقتراح من هيئة التكوين أن يشطب على المتدرب الذي يكون قد أخل بالتزاماته.'),
  LawArticle(id: '9', title: 'الترخيص بالمزاولة', content: 'يرخص وزير العدل للمترشحين الذين نجحوا في اختبار نهاية التكوين بمزاولة مهنة مفوض قضائي بقرار يحدد فيه مقار مكاتبهم ودائرة الاختصاص التي يمكن لهم أن يمارسوا مهنتهم فيها بعد استشارة لجنة تضم من بين أعضائها ممثلين اثنين للمفوضين القضائيين تنتدبهم الهيئة الوطنية للمفوضين القضائيين المنصوص عليها بعده.\\nيحدد تكوين اللجنة المذكورة وطريقة عملها بمقتضى نص تنظيمي.'),
  LawArticle(id: '10', title: 'تأدية اليمين', content: 'يؤدي المفوض القضائي أمام المحكمة الابتدائية التي يقع مكتبه بدائرة نفوذها وقبل مزاولة مهنته، اليمين التالية :\\n« أقسم بالله العظيم أن أقوم بمهامي بإخلاص وأن أنجزها بدقة وأمانة وأن أراعي في كل الأحوال الواجبات التي تفرضها علي، مع الالتزام بالسر المهني ».\\nيشار إلى هذه اليمين في سجل خاص يمسك لهذه الغاية بكتابة ضبط المحكمة المذكورة، ويضع المفوض القضائي بالإضافة إلى ذلك توقيعه وإمضاءه المختصر في هذا السجل الخاص.'),
  LawArticle(id: '11', title: 'الملف الشخصي', content: 'يفتح لدى رئيس المحكمة الابتدائية ملف شخصي لكل مفوض من المفوضين القضائيين العاملين بدائرته تحفظ فيه جميع المستندات والوثائق المتعلقة بحالته المدنية والجامعية والمهنية، كما تضمن فيه نسخ جميع التقارير المحررة في شأنه والمقررات التأديبية أو الزجرية المتخذة في حقه، وكذا تلك الرامية إلى رد اعتباره عند الاقتضاء.'),
  LawArticle(id: '12', title: 'النيابة والمانع', content: 'إذا تغيب مفوض قضائي أو عاقه عائق مؤقت، أصدر رئيس المحكمة الابتدائية لمقره أمرا بتكليف مفوض قضائي آخر بنفس الدائرة للقيام بالإجراءات اللازمة أو عند الاقتضاء بتدبير وتسيير شؤون المكتب وذلك إما تلقائيا أو بطلب من وكيل الملك أو من المفوض القضائي المعني بالأمر.\\nيعين رئيس المحكمة نائبا للمفوض القضائي الذي اعتراه العائق أو المانع لمدة لا تتجاوز ستة أشهر إما باقتراح من المفوض القضائي المعني أو بعد استشارة الهيئة الوطنية للمفوضين القضائيين.\\nإذا وجد مانع يحول دون استمرار قيام المفوض القضائي بمهامه، أشعر رئيس المحكمة وزير العدل الذي يمكنه أن يتخذ قرارا بإعفاء المفوض القضائي من ممارسة المهنة.\\nفي الحالات التي تقتضي تعيين مفوض قضائي آخر إما لتدبير شؤون المكتب أو لتصفيته، يقوم رئيس كتابة الضبط بأمر من رئيس المحكمة بإحصاء الوثائق الموجودة في مكتب المفوض القضائي بحضور ممثل النيابة العامة وممثل الهيئة مع إشعار وزير العدل بذلك.\\nيمكن للمفوض القضائي عند زوال سبب الإعفاء تقديم طلب إلى وزير العدل بإرجاعه إلى عمله.\\nيبت في هذا الطلب خلال ثلاثين يوما من تاريخ تقديمه.'),
  LawArticle(id: '13', title: 'النقل', content: 'يمكن نقل المفوض القضائي بناء على طلبه من دائرة المحكمة التي يوجد بها مكتبه إلى دائرة محكمة أخرى بقرار لوزير العدل بعد استشارة اللجنة المشار إليها في المادة التاسعة أعلاه، مع مراعاة ما تقتضيه المصلحة العامة.'),
  LawArticle(id: '14', title: 'الاستقالة والإعفاء', content: 'يمكن للمفوض القضائي تقديم طلب إعفائه من مزاولة المهنة لوزير العدل تحت إشراف رئيس المحكمة الابتدائية التي يعمل بدائرة نفوذها.\\nلا يحق له أن يكف عن ممارسة عمله إلا بعد قبول هذه الاستقالة.\\nيعين رئيس المحكمة الابتدائية التي يوجد مكتب المفوض القضائي المستقيل بدائرتها، مفوضا قضائيا من نفس المقر لتصفية الأشغال الرائجة بالمكتب باقتراح من الهيئة التي ينتمي إليها، مع مراعاة مقتضيات الفقرة الرابعة من المادة الثانية عشرة أعلاه.'),
  LawArticle(id: '15', title: 'اختصاصات المفوضين', content: 'يختص المفوض القضائي بصفته هاته، مع مراعاة الفقرة الرابعة من هذه المادة، بالقيام بعمليات التبليغ وبإجراءات تنفيذ الأوامر والأحكام والقرارات وكذا كل العقود والسندات التي لها قوة تنفيذية، مع الرجوع إلى القضاء عند وجود أي صعوبة، وذلك باستثناء إجراءات التنفيذ المتعلقة بإفراغ المحلات والبيوعات العقارية وبيع السفن والطائرات والأصول التجارية.\\nيتكلف المفوض القضائي بتسليم استدعاءات التقاضي ضمن الشروط المقررة في قانون المسطرة المدنية وغيرها من القوانين الخاصة، وكذا استدعاءات الحضور المنصوص عليها في قانون المسطرة الجنائية، ويمكن له أن يقوم باستيفاء المبالغ المحكوم بها أو المستحقة بمقتضى سند تنفيذي وإن اقتضى الحال البيع بالمزاد العلني للمنقولات المادية.\\nيقوم المفوض القضائي بتبليغ الإنذارات بطلب من المعني بالأمر مباشرة ما لم ينص القانون على طريقة أخرى للتبليغ.\\nينتدب المفوض القضائي من لدن القضاء للقيام بمعاينات مادية محضة مجردة من كل رأي، ويمكن له أيضا القيام بمعاينات من نفس النوع مباشرة بطلب ممن يعنيه الأمر.\\nيمكن للمفوض القضائي أن ينيب عنه تحت مسؤوليته كاتبا محلفا أو أكثر للقيام بعمليات التبليغ فقط وفق أحكام الباب العاشر من هذا القانون.'),
  LawArticle(id: '16', title: 'إجراءات المفوض', content: 'يمارس المفوض القضائي المهام الموكولة إليه في تنفيذ الأوامر والأحكام والقرارات وينجزها وفقا للقواعد العامة للتنفيذ وذلك تحت مراقبة رئيس المحكمة أو من ينتدبه لهذه الغاية.\\nتشعر المحكمة بمآل ملفات التنفيذ أو بأسباب التأخير في إنجاز الإجراءات.\\nيجب على المفوض القضائي خلال أجل لا يتعدى عشرة أيام من تاريخ تسلمه طلب التنفيذ، تبليغ الطرف المحكوم عليه الحكم المكلف بتنفيذه وإعذاره بالوفاء أو بتعريفه بنواياه.\\nيجب على المفوض القضائي تحرير محضر تنفيذي أو بيان الأسباب التي حالت دون إنجازه وذلك داخل أجل عشرين يوما تبتدئ من تاريخ انتهاء أجل الإعذار.\\nيجب على المفوض القضائي إشعار طالب التنفيذ بالإجراء المتخذ داخل أجل عشرة أيام من تاريخ إنجازه.'),
  LawArticle(id: '17', title: 'الاستعانة بالقوة العمومية', content: 'يمكن للمفوض القضائي عند الاقتضاء الاستعانة بالقوة العمومية أثناء مزاولة مهامه وذلك بعد الحصول على إذن من وكيل الملك طبقا لمقتضيات القانون الجاري به العمل.'),
  LawArticle(id: '18', title: 'التبليغات والمحاضر', content: 'يجب على المفوض القضائي إنجاز الإجراءات والتبليغات والمحاضر في ثلاثة أصول، يسلم الأول إلى الطرف المعني بالأمر معفى من حق التنبر ومن كل شكلية جبائية، ويودع الثاني بملف المحكمة ويحتفظ المفوض القضائي بالثالث بمكتبه.\\nيسأل المفوض القضائي شخصيا عن أخطائه المهنية وكذا عن إعداد المستندات والاحتفاظ بها، ولضمان هذه المسؤولية يجب إبرام عقد تأمين على ذلك.'),
  LawArticle(id: '19', title: 'حفظ الوثائق', content: 'يجب على المفوض القضائي مسك الوثائق التي لها علاقة بحقوق الأطراف لمدة خمس سنوات من تاريخ انتهاء الإجراءات تحال بعدها إلى كتابة ضبط المحكمة المعين بدائرة نفوذها من أجل حفظها مقابل إيصال يسلم له من طرف رئيس كتابة الضبط.\\nتسلم وثائق الإجراءات أو نسخ منها إلى من له الحق فيها بناء على طلبه.'),
  LawArticle(id: '20', title: 'سجل كتابة الضبط', content: 'تمسك كتابة الضبط سجلا وفق نموذج يحدد بقرار لوزير العدل يؤشر على صفحاته رئيس المحكمة الابتدائية المختصة يتضمن الأسماء والعناوين الكاملة للمفوضين القضائيين الموجود محل إقامتهم بدائرة نفوذها وتاريخ التحاقهم بالمهنة، وأدائهم اليمين القانونية ومراجع مقررات تعيينهم، ونماذج من توقيعاتهم وإمضاءاتهم المختصرة.'),
  LawArticle(id: '21', title: 'اختيار المفوض', content: 'يختار الأطراف أو نوابهم المفوض القضائي من بين المفوضين القضائيين الموجودة مقار مكاتبهم بدائرة المحكمة المطلوب القيام بالإجراءات بدائرة نفوذها.'),
  LawArticle(id: '22', title: 'طابع المفوض', content: 'يتعين على الأطراف أو نوابهم أن يبينوا في الطلب اسم المفوض القضائي المختار.\\nيضع المفوض القضائي المختار طابعه وتوقيعه ومحل إقامته في أعلى الصفحة الأولى من الطلب أو يسلم للمعني بالأمر إشهادا بالتزامه بالقيام بالإجراء المطلوب.'),
  LawArticle(id: '23', title: 'استبدال المفوض', content: 'يحق للأطراف استبدال المفوض القضائي في أي مرحلة من مراحل الدعوى أو الإجراءات، مع إشعار كل من المفوض القضائي وكتابة الضبط بذلك.\\nويمكن للمفوض القضائي الاحتفاظ بالوثائق بعد إذن من رئيس المحكمة إلى حين أداء أجرته.'),
  LawArticle(id: '24', title: 'علاقة المفوض بكتابة الضبط', content: 'تسلم الاستدعاءات وشهادات التسليم والطيات المتعلقة بالتبليغ والتنفيذ وجميع الوثائق المرتبطة بها من طرف كتابة الضبط إلى المفوض القضائي بواسطة سجل التداول مرقم الصفحات وموقع من طرف رئيس المحكمة.'),
  LawArticle(id: '25', title: 'المهام والسجل', content: 'يتعين على كل مفوض قضائي أن يمسك سجلا مرقما يثبت فيه كل يوم جميع الإجراءات التي قام بها وبيان أرقام تسلسلها من غير بياض أو إقحام بين السطور أو شطب.\\nيحدد بقرار لوزير العدل نموذج السجل المذكور الذي يوقع على صفحتيه الأولى والأخيرة رئيس المحكمة الابتدائية التي يوجد مقر المفوض القضائي بدائرة نفوذها أو قاض ينتدب لهذا الغرض.'),
  LawArticle(id: '26', title: 'إرجاع الوثائق', content: 'يرجع المفوض القضائي الوثائق بعد إنجاز الإجراءات إلى كتابة الضبط مقابل توقيع.'),
  LawArticle(id: '27', title: 'الحماية الجنائية', content: 'يتمتع المفوض القضائي أثناء مزاولة مهامه، بالحماية التي تنص عليها مقتضيات الفصلين 263 و 267 من القانون الجنائي.'),
  LawArticle(id: '28', title: 'الأجر والتعويض', content: 'يتقاضى المفوض القضائي عن مزاولة مهامه في الميدان الجنائي تعويضا تؤديه الإدارة وفق ما هو مقرر في نص تنظيمي.\\nوفي غير ذلك من الميادين، يتقاضى أجرا عن أعماله حسب تعرفة تحدد بنص تنظيمي تتضمن من بين مقتضياتها مبلغا ثابتا.\\nيؤدى للمفوض القضائي مسبقا المبلغ الثابت.\\nيمنع على المفوض القضائي أن يطلب أو يتسلم مبالغ تفوق الواجبات المحددة.\\nيقوم المفوض القضائي بإنجاز الإجراءات في القضايا المستفيدة من المساعدة القضائية على أن يستخلص مستحقاته عند تصفية الصوائر القضائية.\\nكل مخالفة لهذه المقتضيات تعرض مرتكبها للعقوبات المنصوص عليها في الفصل 243 من القانون الجنائي.'),
  LawArticle(id: '29', title: 'تلقي الأجرة', content: 'يتقاضى المفوض القضائي أجرته مباشرة من طالب الإجراء مقابل تسليم وصل بذلك من كناش ذي جذور.\\nتعتبر أجرة المفوض القضائي جزءا من الصوائر القضائية.'),
  LawArticle(id: '30', title: 'وجوب المباشرة', content: 'يلزم المفوض القضائي ما لم يكن هناك مانع مقبول بمباشرة مهامه كلما طلب منه ذلك وإلا أجبر على إنجازها بمقتضى أمر كتابي يصدره رئيس المحكمة التي يرتبط بها.\\nيمنع على المفوض القضائي أن يحجم عن تقديم المساعدة الواجبة للقضاء والمتقاضين بدون عذر مقبول، كما يمنع على المفوضين القضائيين التواطؤ لنفس الغاية.'),
  LawArticle(id: '31', title: 'موانع شخصية', content: 'يمنع على المفوض القضائي بصفة شخصية أو بواسطة الغير :\\n- أن تكون له أي مصلحة في قضية يباشر فيها مهامه ؛\\n- أن يرصد لحسابه أموالا يكون قد اؤتمن عليها ؛\\n- أن يشارك في المزايدات المتعلقة بالأشياء المكلف ببيعها أو يقبل مشاركة أو عرض زوجه أو أصوله أو فروعه ؛\\n- أن يقتني حقوقا منازعا فيها باشر إحدى إجراءاتها وذلك لنفسه أو لحساب زوجه أو أصوله أو فروعه أو أقاربه إلى الدرجة الرابعة.\\nويجب عليه أن يودع بصندوق المحكمة المبالغ التالية في أجل ثمانية أيام من تاريخ تسلمها :\\n1 - الأموال الناضبة المستخلصة من طرفه لدى مدين أو المسلمة منه طوعا للتحرر من دينه ؛\\n2 - المبالغ المستخلصة من الحجوز لدى الغير ؛\\n3 - المبالغ الناتجة عن بيع المنقولات المادية.'),
  LawArticle(id: '32', title: 'بطلان الإجراء', content: 'يمنع على المفوض القضائي تحت طائلة بطلان الإجراء وتعرضه للمتابعة، أن يباشر أي إجراء لنفسه أو لحساب زوجه أو أصوله أو فروعه أو أقاربه إلى الدرجة الثالثة.'),
  LawArticle(id: '33', title: 'المراقبة', content: 'يراقب رئيس المحكمة المختصة أو من ينتدبه من القضاة لهذه الغاية أعمال وإجراءات المفوضين القضائيين الممارسين في دائرة اختصاصه.\\nترمي هذه المراقبة إلى التحقق على الخصوص من شكليات الإجراءات ووقوعها داخل الأجل وكذا سلامة تداول القيم والأموال التي باشرها المفوض القضائي.\\nإذا تبين لرئيس المحكمة من خلال مراقبته وقوع إخلالات مهنية، حرر تقريرا في الموضوع وأحاله إلى النيابة العامة.\\nيخضع المفوض القضائي كذلك لمراقبة أعوان الإدارة الجبائية كلما طلب منه ذلك ودون نقل أي مستند.'),
  LawArticle(id: '34', title: 'التفتيش', content: 'يقوم وكيل الملك لدى المحكمة الابتدائية المختصة، بتفتيش مكاتب المفوضين القضائيين التابعين لدائرة نفوذه مرة في السنة على الأقل، وكلما اقتضت المصلحة ذلك.\\nإذا تبين لوكيل الملك من خلال تحرياته وقوع إخلالات مهنية خطيرة، أمكنه إيقاف المفوض مؤقتا عن العمل لمدة لا تتجاوز شهرين، وتحريك متابعة تأديبية في حقه.\\nيشعر وكيل الملك وزير العدل بهذه الإجراءات.\\nفي حالة توقف البت في المتابعة التأديبية على مآل المتابعة الجنائية، يمتد مفعول الإيقاف المؤقت عن العمل إلى حين الفصل النهائي.\\nيمكن للمفوض القضائي أن يلجأ إلى غرفة المشورة بالمحكمة الابتدائية المختصة قصد المطالبة برفع حالة الإيقاف المؤقت عن العمل داخل أجل شهر من تاريخ تبليغه بقرار التوقيف.\\nيتعين على غرفة المشورة البت داخل أجل لا يتعدى شهرا من تاريخ وضع الطلب.'),
  LawArticle(id: '35', title: 'انتهاء مفعول الإيقاف', content: 'ينتهي مفعول الإيقاف المؤقت بالبت في المتابعة التأديبية المقامة ضد المفوض القضائي.'),
  LawArticle(id: '36', title: 'تحريك المتابعة', content: 'يحرك وكيل الملك لدى المحكمة الابتدائية المختصة المتابعة التأديبية ضد المفوض القضائي بناء على تقرير من رئيس المحكمة أو على إثر تحرياته التي يقوم بها مباشرة أو بناء على شكاية أو بناء على تقرير من الهيئة الوطنية للمفوضين القضائيين.'),
  LawArticle(id: '37', title: 'غرفة المشورة', content: 'تختص غرفة المشورة بالمحكمة الابتدائية التي يقع مكتب المفوض القضائي بدائرة نفوذها بالبت في المتابعة التأديبية المثارة بشأن كل إخلال بالواجبات المهنية المنصوص عليها في هذا القانون، وذلك بصرف النظر عن المتابعات الجنائية المحتملة.'),
  LawArticle(id: '38', title: 'العقوبات التأديبية', content: 'العقوبات التأديبية هي :\\n1 - الإنذار ؛\\n2 - التوبيخ ؛\\n3 - السحب المؤقت لرخصة مزاولة المهنة لمدة أقصاها ستة أشهر ؛\\n4 - السحب النهائي للرخصة المذكورة.'),
  LawArticle(id: '39', title: 'جلسة الاستماع', content: 'تستدعي غرفة المشورة بالمحكمة الابتدائية المختصة المفوض القضائي قبل عشرة أيام من تاريخ الجلسة للاستماع إليه وتقديم ملاحظاته ومستنتجاته حول موضوع المتابعة مع حقه في الاستعانة بمحام.\\nيكون حضور النيابة العامة بالجلسة وجوبيا.\\nيتعين على غرفة المشورة البت داخل أجل ستين يوما ابتداء من تاريخ إحالة الملف إليها.'),
  LawArticle(id: '40', title: 'استئناف المقرر', content: 'يستأنف المقرر التأديبي الصادر في حق المفوض القضائي أمام غرفة المشورة بمحكمة الاستئناف المختصة داخل أجل 15 يوما كاملة من تاريخ تبليغ المقرر وفقا للإجراءات المنصوص عليها في هذا القانون وفي قانون المسطرة المدنية.\\nيبدأ سريان أجل الاستئناف بالنسبة للنيابة العامة من تاريخ النطق بالحكم.\\nتبت غرفة المشورة داخل أجل ثلاثة أشهر من تاريخ إحالة مقال الاستئناف إليها.\\nيسهر وكيل الملك المختص على تنفيذ المقرر التأديبي.\\nتخصم مدة الإيقاف المؤقت عند الاقتضاء من مدة السحب المؤقت لرخصة مزاولة المهنة.\\nبعد انتهاء مدة التأديب أو في حالة البت بعدم المتابعة يستأنف المفوض القضائي عمله تلقائيا مع إشعار رئيس المحكمة بذلك.'),
  LawArticle(id: '41', title: 'الكتاب المحلفون الإلحاق', content: 'يمكن للمفوض القضائي أن يلحق بمكتبه تحت مسؤوليته كاتبا محلفا أو أكثر، للنيابة عنه في الإجراءات المتعلقة بالتبليغ.\\nيتم هذا الإلحاق وفق عقد يتحدد نموذجه بقرار من وزير العدل.\\nيؤدي الكاتب المحلف أمام المحكمة الابتدائية التي يقع مكتب المفوض القضائي بدائرة نفوذها اليمين القانونية المنصوص عليها في المادة العاشرة أعلاه، وذلك بعدما يتأكد رئيس المحكمة من توفر الشروط القانونية فيه، ويستعين برأي وكيل الملك في الموضوع.\\nيخبر رئيس المحكمة المذكورة بعد ذلك وزير العدل وكذا الهيئة بإلحاق الكاتب المحلف بمكتب المفوض القضائي.'),
  LawArticle(id: '42', title: 'شروط الكاتب المحلف', content: 'يشترط في المترشح لمزاولة مهنة كاتب محلف ما يلي :\\n1 - أن يكون من جنسية مغربية ؛\\n2 - أن يبلغ من العمر عشرين سنة وأن لا يتجاوز أربعين سنة ؛\\n3 - أن يثبت قدرته الصحية على مزاولة المهنة ؛\\n4 - أن يكون حاصلا على شهادة الباكالوريا أو ما يعادلها ؛\\n5 - أن يكون متمتعا بحقوقه المدنية ؛\\n6 - أن لا يكون محكوما عليه من أجل جناية أو جنحة بعقوبة حبس نافذة أو موقوف التنفيذ باستثناء الجرائم غير العمدية، وأن لا يكون محكوما عليه بجريمة من جرائم الأموال ولو بمجرد غرامة ما لم يرد اعتباره.'),
  LawArticle(id: '43', title: 'دائرة الاِختصاص', content: 'يقوم الكاتب المحلف بعمله داخل دائرة الاختصاص المحددة للمفوض القضائي الذي ينوب عنه ولا يجوز له أن يتجاوزها.'),
  LawArticle(id: '44', title: 'توقيع وتأشير المفوض', content: 'يجب على المفوض القضائي تحت طائلة البطلان :\\n- أن يوقع أصول التبليغات المعهود إلى الكتاب المحلفين بإنجازها ؛\\n- أن يؤشر على البيانات التي يسجلها الكتاب المحلفون في الأصول المذكورة.'),
  LawArticle(id: '45', title: 'مسؤولية المفوض المدنية', content: 'يكون المفوض القضائي مسؤولا مدنيا عن أوجه البطلان والغرامات والإرجاعات والمصاريف والتعويضات التي يتسبب فيها الكتاب المحلفون خلال القيام بالنيابة عنه.'),
  LawArticle(id: '46', title: 'إنهاء إلحاق الكاتب', content: 'يمكن لرئيس المحكمة الابتدائية المختصة أن يضع حدا لإلحاق الكاتب المحلف عند ثبوت مخالفة خطيرة في حقه.\\nيمكن للكاتب المحلف استئناف هذا المقرر داخل الأجل ووفق المسطرة المنصوص عليهما في المادة 40 أعلاه.\\nيجب على المفوض القضائي إخبار رئيس المحكمة الابتدائية ووكيل الملك والهيئة التي ينتمي إليها بتخليه عن الكاتب المحلف أو استقالته.'),
  LawArticle(id: '47', title: 'المشاركة بين المفوضين', content: 'يمكن لمفوضين قضائيين اثنين أو أكثر إبرام عقد مشاركة إذا كانوا معينين في نفس الدائرة الترابية للمحكمة الابتدائية.'),
  LawArticle(id: '48', title: 'عقد المشاركة', content: 'تبرم المشاركة بمقتضى عقد نموذجي يحدد بقرار لوزير العدل.\\nلا يصبح العقد نافذا إلا بعد إخبار وزير العدل.\\nيمكن لوزير العدل أن يطلب داخل أجل 60 يوما من تاريخ التبليغ من المفوضين القضائيين تغيير اتفاقهم إذا اعتبره متناقضا مع قواعد المهنة.'),
  LawArticle(id: '49', title: 'التسيير التضامني', content: 'يقوم المفوضون القضائيون المتشاركون تضامنا فيما بينهم بتسيير وإدارة وإنجاز الإجراءات.\\nتسري حالة المنع المنصوص عليها في المادة 32 بالنسبة لأحد المفوضين القضائيين على باقي المتشاركين معه في نفس المكتب.'),
  LawArticle(id: '50', title: 'المسؤولية', content: 'يتحمل كل متشارك مسؤولية الإجراءات المنجزة من طرفه مهنيا وجنائيا.'),
  LawArticle(id: '51', title: 'انتهاء المشاركة', content: 'تنتهي المشاركة بأحد الأسباب التالية :\\n- انتهاء المدة التي حددت لها في عقد المشاركة ؛\\n- وفاة أحد المتشاركين ولم يبق إلا متشارك واحد ؛\\n- فقدان أهلية أحد المتشاركين أو سحب الرخصة منه ولم يبق إلا متشارك واحد ؛\\n- اتفاق المتشاركين ؛\\n- حكم قضائي.'),
  LawArticle(id: '52', title: 'العمليات والتصفية', content: 'تجرى عمليات تصفية المشاركة بحضور المفوضين القضائيين المتشاركين أو من يمثلهم تحت مراقبة وكيل الملك لدى المحكمة الابتدائية التي يمارس المفوضون القضائيون مهامهم بدائرة نفوذها، وكذا عضوين من الجهة التمثيلية لهيئة المفوضين القضائيين جهويا.\\nيمكن عند الاقتضاء، الاستعانة بمدقق الحسابات.\\nتثبت هذه العمليات في محضر.'),
  LawArticle(id: '53', title: 'العقوبات الجنائية', content: 'يعاقب المفوض القضائي بغرامة من ألف درهم إلى عشرة آلاف درهم، وبحبس تتراوح مدته من شهر إلى سنتين أو بإحدى العقوبتين فقط عن كل مخالفة لمقتضيات المادتين 31 و 32 من هذا القانون، ما لم يكن الفعل المعاقب عليه يوجب تطبيق عقوبة أشد بمقتضى القانون الجنائي، وذلك بصرف النظر عن العقوبات التأديبية التي يمكن أن يتعرض لها.'),
  LawArticle(id: '54', title: 'عقوبة السمسرة', content: 'يعاقب كل شخص يقوم بسمسرة الزبناء أو جلبهم لفائدة المفوض القضائي بثلاثة أشهر إلى سنة حبسا وبغرامة من 500 إلى 1.000 درهم.'),
  LawArticle(id: '55', title: 'انتحال الصفة', content: 'يعاقب كل شخص نسب لنفسه من غير حق صفة مفوض قضائي أو زاول مهامه دون أن يكون مرخصا له بذلك بالعقوبة المنصوص عليها في الفصل 381 من القانون الجنائي.'),
  LawArticle(id: '56', title: 'الكيان والمقر', content: 'تحدث بمقتضى هذا القانون هيئة وطنية للمفوضين القضائيين تتمتع بالشخصية المعنوية، وتضم جميع المفوضين القضائيين.\\nيوجد مقر الهيئة بالرباط.\\nويتم تنظيم هذه الهيئة بنص تنظيمي.'),
  LawArticle(id: '57', title: 'الاستمرار في المزاولة', content: 'يستمر جميع الأعوان القضائيين المرخص لهم قبل دخول هذا القانون حيز التنفيذ في ممارسة المهنة وكذا الكتاب المحلفون الملحقون بمكاتبهم.'),
  LawArticle(id: '58', title: 'نسخ المقتضيات', content: 'تنسخ مقتضيات القانون رقم 41.80 بإحداث هيئة للأعوان القضائيين وتنظيمها الصادر بتنفيذه الظهير الشريف رقم 1.80.440 بتاريخ 17 من صفر 1401 (25 ديسمبر 1980) والظهير الشريف رقم 1.93.138 الصادر في 22 من ربيع الأول 1414 (10 سبتمبر 1993) المعتبر بمثابة قانون يغير ويتمم بموجبه القانون رقم 41.80 المتعلق بإحداث هيئة للأعوان القضائيين وتنظيمها.'),
  LawArticle(id: '59', title: 'سريان المفعول', content: 'يسري مفعول هذا القانون بعد ثلاثة أشهر من نشره بالجريدة الرسمية.'),
];
"""

with codecs.open('c:/src/nour/lib/models/library_data.dart', 'r', encoding='utf-8') as f:
    content = f.read()

content = re.sub(r'const List<LawArticle> law8103Data = \[.*?\];', new_law_data, content, flags=re.DOTALL)

with codecs.open('c:/src/nour/lib/models/library_data.dart', 'w', encoding='utf-8') as f:
    f.write(content)

print("INJECTION SUCCESSFUL")
